ALTER PROCEDURE ST_INSERIR_MORTALIDADE (
    P_OBSERVACAO VARCHAR(255),
    P_QTD_MORTA INTEGER,
    P_DATA_MORTALIDADE DATE,
    P_ID_LOTE_FK INTEGER)
RETURNS (
    OUT_PERCENTUAL_ACUMULADO NUMERIC(15,2))
AS
declare variable v_qtd_inicial integer;
declare variable v_total_morto_anterior integer;
BEGIN

  SELECT QUANTIDADE_INICIAL FROM TAB_LOTES_AVES 
  WHERE ID_LOTE = :p_id_lote_fk 
  INTO :v_qtd_inicial;


  SELECT COALESCE(SUM(QUANTIDADE_MORTA), 0) FROM TAB_MORTALIDADE 
  WHERE ID_LOTE_FK = :p_id_lote_fk 
  INTO :v_total_morto_anterior;


  IF ((v_total_morto_anterior + p_qtd_morta) > v_qtd_inicial) THEN
    EXCEPTION ERR_VALIDACAO;


  INSERT INTO TAB_MORTALIDADE (ID_LOTE_FK, DATA_MORTALIDADE, QUANTIDADE_MORTA, OBSERVACAO)
  VALUES (:p_id_lote_fk, :p_data_mortalidade, :p_qtd_morta, :p_observacao);


  out_percentual_acumulado = ((CAST(v_total_morto_anterior + p_qtd_morta AS DOUBLE PRECISION) / v_qtd_inicial) * 100);
  
  SUSPEND; 
END^




